// Generates js/runtime-source.js — a tiny static module that exposes the
// source TEXT of every runtime JS file via window._runtimeSource. The
// editor's "Export Game" export reads from this object to inline the
// runtime into the standalone HTML.
//
// Why this exists: file:// has no fetch() access to local files in any
// modern browser, so the export can't load runtime JS at click time when
// the editor is opened directly (without a local server). Bundling the
// source as a regular <script>-loadable JS file sidesteps that — script
// tags work fine from file://.
//
// Re-run after editing any runtime JS file:
//     node tools/bundle-runtime.js
// (CI / test suite verifies the bundle is current; see
// tests/runtime-bundle.test.js.)

import { readFileSync, writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const ROOT = resolve(__dirname, '..');

// Files in the order the editor (and the standalone) loads them. The
// standalone export uses this list to know what to inline; the editor
// loads them via individual <script> tags for normal development. Keep
// the two lists in sync — there's only one source of truth here.
export const RUNTIME_FILES = [
    'js/c64lib.js',
    'js/c64Screen.js',
    'js/d64lib.js',
    'js/gmOpcodes.js',
    'js/gmSprite.js',
    'js/gmScene.js',
    'js/gmSound.js',
    'js/gmMusic.js',
    'js/gmCharset.js',
    'js/gmParser.js',
    'js/gmRuntime.js'
];

const HEADER = `// This file is generated by tools/bundle-runtime.js.
// DO NOT EDIT — re-run \`node tools/bundle-runtime.js\` after changing
// any runtime JS file. The test suite verifies this file is current.
//
// Provides window._runtimeSource = { '<path>': '<source text>', ... }
// for the editor's "Export Game" export to inline into standalone HTML.
`;

export function generate() {
    const entries = {};
    for (const f of RUNTIME_FILES) {
        entries[f] = readFileSync(resolve(ROOT, f), 'utf8');
    }
    return HEADER + `window._runtimeSource = ${JSON.stringify(entries, null, 2)};\n`;
}

// CLI: write the bundle to disk.
if (import.meta.url === `file://${process.argv[1]}`) {
    const out = generate();
    const target = resolve(ROOT, 'js', 'runtime-source.js');
    writeFileSync(target, out);
    console.log(`wrote ${target} (${out.length.toLocaleString()} bytes)`);
}
